		// Periodically flush accumulated text/thinking messages.
		ticker := time.NewTicker(500 * time.Millisecond)
		defer ticker.Stop()

		done := make(chan struct{})
		go func() {
			for {
				select {
				case <-ticker.C:
					flush()
				case <-done:
					return
				}
			}
		}()

		for msg := range session.Messages {
			switch msg.Type {
			case agent.MessageToolUse:
				n := toolCount.Add(1)
				taskLog.Info(fmt.Sprintf("tool #%d: %s", n, msg.Tool))
				if msg.CallID != "" {
					mu.Lock()
					callIDToTool[msg.CallID] = msg.Tool
					mu.Unlock()
				}
				s := seq.Add(1)
				mu.Lock()
				batch = append(batch, TaskMessageData{
					Seq:   int(s),
					Type:  "tool_use",
					Tool:  msg.Tool,
					Input: msg.Input,
				})
				mu.Unlock()
			case agent.MessageToolResult:
				s := seq.Add(1)
				output := msg.Output
				if len(output) > 8192 {
					output = output[:8192]
				}
				// Resolve tool name from callID if not set directly.
				toolName := msg.Tool
				if toolName == "" && msg.CallID != "" {
					mu.Lock()
					toolName = callIDToTool[msg.CallID]
					mu.Unlock()
				}
				mu.Lock()
				batch = append(batch, TaskMessageData{
					Seq:    int(s),
					Type:   "tool_result",
					Tool:   toolName,
					Output: output,
				})
				mu.Unlock()
			case agent.MessageThinking:
				if msg.Content != "" {
					mu.Lock()
					pendingThinking.WriteString(msg.Content)
					mu.Unlock()
				}
			case agent.MessageText:
				if msg.Content != "" {
					taskLog.Debug("agent", "text", truncateLog(msg.Content, 200))
					mu.Lock()
					pendingText.WriteString(msg.Content)
					mu.Unlock()
				}
			case agent.MessageError:
				taskLog.Error("agent error", "content", msg.Content)
				s := seq.Add(1)
				mu.Lock()
				batch = append(batch, TaskMessageData{
					Seq:     int(s),
					Type:    "error",
					Content: msg.Content,
				})
				mu.Unlock()
			}
		}

		close(done)
		flush() // Final flush after channel closes.
	}()

	result := <-session.Result
	elapsed := time.Since(taskStart).Round(time.Second)
	taskLog.Info("agent finished",
		"status", result.Status,
		"duration", elapsed.String(),
		"tools", toolCount.Load(),
	)

	switch result.Status {
	case "completed":
		if result.Output == "" {
			return TaskResult{}, fmt.Errorf("%s returned empty output", provider)
		}
		if strings.TrimSpace(task.Mode) == "plan" {
			planStatus, planRequiresDecision, planQuestions := analyzePlanOutput(result.Output)
			return TaskResult{
				Status:               "completed",
				Comment:              result.Output,
				Summary:              summarizePlanOutput(result.Output),
				PlanStatus:           planStatus,
				PlanRequiresDecision: planRequiresDecision,
				PlanQuestions:        planQuestions,
				SessionID:            result.SessionID,
				WorkDir:              env.WorkDir,
			}, nil
		}
		branchName := detectGitBranch(env.WorkDir)
		prURL := extractFirstURL(result.Output, githubPRPattern)
		compareURL := extractFirstURL(result.Output, githubComparePattern)
		if compareURL == "" {
			compareURL = buildGitHubCompareURL(task.SelectedRepoURL, env.WorkDir, branchName)
		}
		deliveryState, handoffReason, summary := inferDeliveryMetadata(result.Output, branchName, prURL, compareURL)
		return TaskResult{
			Status:        "completed",
			Comment:       result.Output,
			Summary:       summary,
			PRURL:         prURL,
