	}
	updated, err := s.Queries.UpdateIssueExecutionStage(ctx, db.UpdateIssueExecutionStageParams{
		ID:             issue.ID,
		ExecutionStage: stage,
	})
	if err != nil {
		return db.Issue{}, false, err
	}
	s.broadcastIssueUpdated(updated)
	return updated, true, nil
}

