// Drive the session lifecycle in a goroutine.
// Shutdown sequence: lifecycle goroutine closes stdin + cancels context →
// codex process exits → reader goroutine's scanner.Scan() returns false →
// readerDone closes → lifecycle goroutine collects final output and sends Result.
go func() {
	defer cancel()
	defer close(msgCh)
	defer close(resCh)
	defer func() {
		stdin.Close()
		_ = cmd.Wait()
	}()

	startTime := time.Now()
	finalStatus := "completed"
	var finalError string

	// 1. Initialize handshake
	_, err := c.request(runCtx, "initialize", map[string]any{
		"clientInfo": map[string]any{
			"name":    "multica-agent-sdk",
			"title":   "Multica Agent SDK",
			"version": "0.2.0",
		},
		"capabilities": map[string]any{
			"experimentalApi": true,
		},
	})
	if err != nil {
		finalStatus = "failed"
		finalError = fmt.Sprintf("codex initialize failed: %v", err)
		resCh <- Result{Status: finalStatus, Error: finalError, DurationMs: time.Since(startTime).Milliseconds()}
		return
	}
	c.notify("initialized")

	modesResult, err := c.request(runCtx, "collaborationMode/list", map[string]any{})
	if err != nil {
		b.cfg.Logger.Warn("codex collaborationMode/list failed", "error", err)
	}
	availableModes := extractCollaborationModes(modesResult)

	// 2. Start thread
	threadResult, err := c.request(runCtx, "thread/start", map[string]any{
		"model":                  nilIfEmpty(opts.Model),
		"modelProvider":          nil,
		"profile":                nil,
		"cwd":                    opts.Cwd,
		"approvalPolicy":         "never",
		"sandbox":                "danger-full-access",
		"config":                 nil,
		"baseInstructions":       nil,
		"developerInstructions":  nilIfEmpty(opts.SystemPrompt),
		"compactPrompt":          nil,
		"includeApplyPatchTool":  nil,
		"experimentalRawEvents":  false,
		"persistExtendedHistory": true,
	})
	if err != nil {
		finalStatus = "failed"
		finalError = fmt.Sprintf("codex thread/start failed: %v", err)
		resCh <- Result{Status: finalStatus, Error: finalError, DurationMs: time.Since(startTime).Milliseconds()}
		return
	}

	threadID := extractThreadID(threadResult)
	if threadID == "" {
		finalStatus = "failed"
		finalError = "codex thread/start returned no thread ID"
		resCh <- Result{Status: finalStatus, Error: finalError, DurationMs: time.Since(startTime).Milliseconds()}
		return
	}
	c.threadID = threadID
	b.cfg.Logger.Info("codex thread started", "thread_id", threadID)

// Package execenv manages isolated per-task execution environments for the daemon.
// Each task gets its own directory with injected context files. Repositories are
// checked out on demand by the agent via `multica repo checkout`.
package execenv

import (
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
)

// RepoContextForEnv describes a workspace repo available for checkout.
type RepoContextForEnv struct {
	URL         string // remote URL
	Description string // human-readable description
}

// PrepareParams holds all inputs needed to set up an execution environment.
type PrepareParams struct {
	WorkspacesRoot string            // base path for all envs (e.g., ~/multica_workspaces)
	WorkspaceID    string            // workspace UUID — tasks are grouped under this
	TaskID         string            // task UUID — used for directory name
	AgentName      string            // for git branch naming only
	Provider       string            // agent provider ("claude", "codex") — determines skill injection paths
	Task           TaskContextForEnv // context data for writing files
}

// TaskContextForEnv is the subset of task context used for writing context files.
type TaskContextForEnv struct {
	IssueID                 string
	Mode                    string
	ParentTaskID            string
	SwarmRole               string
	TriggerCommentID        string // comment that triggered this task (empty for on_assign)
	AgentName               string
	AgentInstructions       string // agent identity/persona instructions, injected into CLAUDE.md
	AgentSkills             []SkillContextForEnv
	RunMemories             []RunMemoryContextForEnv
	Repos                   []RepoContextForEnv // workspace repos available for checkout
	SelectedRepoURL         string
	SelectedRepoDescription string
	IdeaSlug                string
	IdeaCode                string
	IdeaTitle               string
}

// RunMemoryContextForEnv describes recent execution memory injected into the workdir.
type RunMemoryContextForEnv struct {
	Kind      string
	Title     string
	Content   string
	CreatedAt string
}

// SkillContextForEnv represents a skill to be written into the execution environment.
type SkillContextForEnv struct {
	Name    string
	Content string
	Files   []SkillFileContextForEnv
}

// SkillFileContextForEnv represents a supporting file within a skill.
type SkillFileContextForEnv struct {
	Path    string
	Content string
}

// Environment represents a prepared, isolated execution environment.
type Environment struct {
	// RootDir is the top-level env directory ({workspacesRoot}/{task_id_short}/).
	RootDir string
	// WorkDir is the directory to pass as Cwd to the agent ({RootDir}/workdir/).
	WorkDir string
	// CodexHome is the path to the per-task CODEX_HOME directory (set only for codex provider).
	CodexHome string
	// TraeConfigFile points to the per-task Trae config file when the provider is Trae.
	TraeConfigFile string
	// TraeTrajectoryFile points to the per-task Trae trajectory file.
	TraeTrajectoryFile string
	// HermesHome is the per-task HERMES_HOME directory.
	HermesHome string

	logger *slog.Logger // for cleanup logging
}

// Prepare creates an isolated execution environment for a task.
// The workdir starts empty (no repo checkouts). The agent checks out repos
// on demand via `multica repo checkout <url>`.
func Prepare(params PrepareParams, logger *slog.Logger) (*Environment, error) {
	if params.WorkspacesRoot == "" {
		return nil, fmt.Errorf("execenv: workspaces root is required")
	}
	if params.WorkspaceID == "" {
		return nil, fmt.Errorf("execenv: workspace ID is required")
	}
	if params.TaskID == "" {
		return nil, fmt.Errorf("execenv: task ID is required")
	}

	envRoot := filepath.Join(params.WorkspacesRoot, params.WorkspaceID, shortID(params.TaskID))

	// Remove existing env if present (defensive — task IDs are unique).
	if _, err := os.Stat(envRoot); err == nil {
		if err := os.RemoveAll(envRoot); err != nil {
			return nil, fmt.Errorf("execenv: remove existing env: %w", err)
		}
	}

	// Create directory tree.
	workDir := filepath.Join(envRoot, "workdir")
	for _, dir := range []string{workDir, filepath.Join(envRoot, "output"), filepath.Join(envRoot, "logs")} {
		if err := os.MkdirAll(dir, 0o755); err != nil {
			return nil, fmt.Errorf("execenv: create directory %s: %w", dir, err)
		}
	}

	env := &Environment{
		RootDir: envRoot,
		WorkDir: workDir,
		logger:  logger,
	}

	// Write context files into workdir (skills go to provider-native paths).
	if err := writeContextFiles(workDir, params.Provider, params.Task); err != nil {
		return nil, fmt.Errorf("execenv: write context files: %w", err)
	}

	// For Codex, set up a per-task CODEX_HOME seeded from ~/.codex/ with skills.
	if params.Provider == "codex" {
		codexHome := filepath.Join(envRoot, "codex-home")
		if err := prepareCodexHome(codexHome, logger); err != nil {
			return nil, fmt.Errorf("execenv: prepare codex-home: %w", err)
		}
		if len(params.Task.AgentSkills) > 0 {
			if err := writeSkillFiles(filepath.Join(codexHome, "skills"), params.Task.AgentSkills); err != nil {
				return nil, fmt.Errorf("execenv: write codex skills: %w", err)
			}
		}
		env.CodexHome = codexHome
	}
	if params.Provider == "trae" {
		traeHome := filepath.Join(envRoot, "trae-home")
		traeConfigFile, trajectoryFile, err := prepareTraeHome(traeHome, logger)
		if err != nil {
			return nil, fmt.Errorf("execenv: prepare trae-home: %w", err)
		}
		env.TraeConfigFile = traeConfigFile
		env.TraeTrajectoryFile = trajectoryFile
	}
	if params.Provider == "hermes" {
		hermesHome := filepath.Join(envRoot, "hermes-home")
		if err := prepareHermesHome(hermesHome, logger); err != nil {
			return nil, fmt.Errorf("execenv: prepare hermes-home: %w", err)
		}
		if len(params.Task.AgentSkills) > 0 {
			if err := writeSkillFiles(filepath.Join(hermesHome, "skills"), params.Task.AgentSkills); err != nil {
				return nil, fmt.Errorf("execenv: write hermes skills: %w", err)
			}
		}
		env.HermesHome = hermesHome
	}

	logger.Info("execenv: prepared env", "root", envRoot, "repos_available", len(params.Task.Repos))
	return env, nil
}

// Reuse wraps an existing workdir into an Environment and refreshes context files.
// Returns nil if the workdir does not exist (caller should fall back to Prepare).
func Reuse(workDir, provider string, task TaskContextForEnv, logger *slog.Logger) *Environment {
	if _, err := os.Stat(workDir); err != nil {
		return nil
	}

	env := &Environment{
		RootDir: filepath.Dir(workDir),
		WorkDir: workDir,
		logger:  logger,
	}

	switch provider {
	case "codex":
		codexHome := filepath.Join(env.RootDir, "codex-home")
		if err := prepareCodexHome(codexHome, logger); err != nil {
			logger.Warn("execenv: refresh codex-home failed", "error", err)
		} else {
			if len(task.AgentSkills) > 0 {
				if err := writeSkillFiles(filepath.Join(codexHome, "skills"), task.AgentSkills); err != nil {
					logger.Warn("execenv: refresh codex skills failed", "error", err)
				}
			}
			env.CodexHome = codexHome
		}
	case "trae":
		traeHome := filepath.Join(env.RootDir, "trae-home")
		traeConfigFile, trajectoryFile, err := prepareTraeHome(traeHome, logger)
		if err != nil {
			logger.Warn("execenv: refresh trae-home failed", "error", err)
		} else {
			env.TraeConfigFile = traeConfigFile
			env.TraeTrajectoryFile = trajectoryFile
		}
	case "hermes":
		hermesHome := filepath.Join(env.RootDir, "hermes-home")
		if err := prepareHermesHome(hermesHome, logger); err != nil {
			logger.Warn("execenv: refresh hermes-home failed", "error", err)
		} else {
			if len(task.AgentSkills) > 0 {
				if err := writeSkillFiles(filepath.Join(hermesHome, "skills"), task.AgentSkills); err != nil {
					logger.Warn("execenv: refresh hermes skills failed", "error", err)
				}
			}
			env.HermesHome = hermesHome
		}
	}

	// Refresh context files (issue_context.md, skills).
	if err := writeContextFiles(workDir, provider, task); err != nil {
		logger.Warn("execenv: refresh context files failed", "error", err)
	}

	logger.Info("execenv: reusing env", "workdir", workDir)
	return env
}

// Cleanup tears down the execution environment.
// If removeAll is true, the entire env root is deleted. Otherwise, workdir is
// removed but output/ and logs/ are preserved for debugging.
func (env *Environment) Cleanup(removeAll bool) error {
	if env == nil {
		return nil
	}

	if removeAll {
		if err := os.RemoveAll(env.RootDir); err != nil {
			env.logger.Warn("execenv: cleanup removeAll failed", "error", err)
			return err
		}
		return nil
	}

	// Partial cleanup: remove workdir, keep output/ and logs/.
	if err := os.RemoveAll(env.WorkDir); err != nil {
		env.logger.Warn("execenv: cleanup workdir failed", "error", err)
		return err
	}
	return nil
