175	// FanOutTask enqueues child tasks for the same issue under a parent task.
176	// Child tasks reuse the existing queue/claim model but can run in parallel
177	// when they share the same parent_task_id.
178	func (s *TaskService) FanOutTask(ctx context.Context, parentTaskID, issueID pgtype.UUID, specs []FanOutTaskSpec) ([]db.AgentTaskQueue, error) {
179		if len(specs) == 0 {
180			return nil, fmt.Errorf("at least one fan-out task is required")
181		}
182	
183		parentTask, err := s.Queries.GetAgentTask(ctx, parentTaskID)
184		if err != nil {
185			return nil, fmt.Errorf("load parent task: %w", err)
186		}
187		if parentTask.IssueID != issueID {
188			return nil, fmt.Errorf("parent task does not belong to issue")
189		}
190	
191		issue, err := s.Queries.GetIssue(ctx, issueID)
192		if err != nil {
193			return nil, fmt.Errorf("load issue: %w", err)
194		}
195	
196		queued := make([]db.AgentTaskQueue, 0, len(specs))
197		for _, spec := range specs {
198			mode := NormalizeTaskMode(spec.Mode)
199			agentRecord, err := s.Queries.GetAgent(ctx, spec.AgentID)
200			if err != nil {
201				return nil, fmt.Errorf("load agent: %w", err)
202			}
203			if agentRecord.ArchivedAt.Valid {
204				return nil, fmt.Errorf("agent is archived")
205			}
206			if !agentRecord.RuntimeID.Valid {
207				return nil, fmt.Errorf("agent has no runtime")
208			}
209			if err := ValidateRuntimeExecutionModeSupport(ctx, s.Queries, agentRecord.RuntimeID, mode); err != nil {
210				return nil, err
211			}
212	
213			task, err := s.Queries.CreateAgentTask(ctx, db.CreateAgentTaskParams{
214				AgentID:       spec.AgentID,
215				RuntimeID:     agentRecord.RuntimeID,
216				IssueID:       issue.ID,
217				Priority:      priorityToInt(issue.Priority),
218				Mode:          mode,
219				TriggerSource: TaskTriggerSourceSwarm,
220				ParentTaskID:  parentTaskID,
221				SwarmRole:     strings.TrimSpace(spec.Role),
222			})
223			if err != nil {
224				return nil, fmt.Errorf("create child task: %w", err)
225			}
226			queued = append(queued, task)
227			slog.Info("fan-out task enqueued",
228				"task_id", util.UUIDToString(task.ID),
229				"parent_task_id", util.UUIDToString(parentTaskID),
230				"issue_id", util.UUIDToString(issue.ID),
231				"agent_id", util.UUIDToString(spec.AgentID),
232				"mode", mode,
233				"role", strings.TrimSpace(spec.Role),
234			)
235		}
236	
237		if _, _, err := s.setIssueExecutionStage(ctx, issue, QueueStageForMode(specs[0].Mode)); err != nil {
238			slog.Warn("fan-out: failed to update execution stage", "issue_id", util.UUIDToString(issue.ID), "error", err)
239		}
240	
241		return queued, nil
242	}
