 11	// hermesBackend implements Backend by spawning Hermes Agent in one-shot query mode.
 12	// Hermes does not expose a structured event stream here, so stdout is treated as
 13	// plain assistant text and stderr is forwarded as log events.
 14	type hermesBackend struct {
 15		cfg Config
 16	}
 17	
 18	func (b *hermesBackend) Execute(ctx context.Context, prompt string, opts ExecOptions) (*Session, error) {
 19		execPath := b.cfg.ExecutablePath
 20		if execPath == "" {
 21			execPath = "hermes"
 22		}
 23		if err := validateExecutable(execPath, b.cfg.Sandbox); err != nil {
 24			return nil, fmt.Errorf("hermes executable not available: %w", err)
 25		}
 26	
 27		timeout := opts.Timeout
 28		if timeout == 0 {
 29			timeout = 20 * time.Minute
 30		}
 31		runCtx, cancel := context.WithTimeout(ctx, timeout)
 32	
 33		args := []string{"chat", "--quiet", "-q", prompt}
 34		if opts.Model != "" {
 35			args = append(args, "--model", opts.Model)
 36		}
 37		if opts.ResumeSessionID != "" {
 38			args = append(args, "--resume", opts.ResumeSessionID)
 39		}
 40	
 41		cmd, err := buildCommand(runCtx, execPath, args, opts.Cwd, b.cfg.Env, b.cfg.Sandbox)
 42		if err != nil {
 43			cancel()
 44			return nil, fmt.Errorf("build hermes command: %w", err)
 45		}
 46	
 47		stdout, err := cmd.StdoutPipe()
 48		if err != nil {
 49			cancel()
 50			return nil, fmt.Errorf("hermes stdout pipe: %w", err)
 51		}
 52		stderr, err := cmd.StderrPipe()
 53		if err != nil {
 54			cancel()
 55			return nil, fmt.Errorf("hermes stderr pipe: %w", err)
 56		}
 57	
 58		if err := cmd.Start(); err != nil {
 59			cancel()
 60			return nil, fmt.Errorf("start hermes: %w", err)
 61		}
 62	
 63		b.cfg.Logger.Info("hermes started", "pid", cmd.Process.Pid, "cwd", opts.Cwd, "model", opts.Model)
 64	
 65		msgCh := make(chan Message, 256)
 66		resCh := make(chan Result, 1)
 67	
 68		go func() {
 69			defer cancel()
 70			defer close(msgCh)
 71			defer close(resCh)
 72	
 73			startTime := time.Now()
 74			var output strings.Builder
 75			finalStatus := "completed"
 76			var finalError string
 77			sessionID := opts.ResumeSessionID
 78	
 79			trySend(msgCh, Message{Type: MessageStatus, Status: "running"})
 80	
 81			stderrDone := make(chan struct{})
 82			go func() {
 83				defer close(stderrDone)
 84				scanner := bufio.NewScanner(stderr)
 85				scanner.Buffer(make([]byte, 0, 64*1024), 1024*1024)
 86				for scanner.Scan() {
 87					line := strings.TrimSpace(scanner.Text())
 88					if line == "" {
 89						continue
 90					}
 91					trySend(msgCh, Message{Type: MessageLog, Level: "info", Content: line})
 92				}
 93			}()
 94	
 95			scanner := bufio.NewScanner(stdout)
 96			scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
 97			for scanner.Scan() {
 98				line := scanner.Text()
 99				if strings.TrimSpace(line) == "" {
100					continue
101				}
102				if output.Len() > 0 {
103					output.WriteByte('\n')
104				}
105				output.WriteString(line)
106				trySend(msgCh, Message{Type: MessageText, Content: line})
107			}
108	
109			<-stderrDone
110			exitErr := cmd.Wait()
111			duration := time.Since(startTime)
112	
113			if runCtx.Err() == context.DeadlineExceeded {
114				finalStatus = "timeout"
115				finalError = fmt.Sprintf("hermes timed out after %s", timeout)
116			} else if runCtx.Err() == context.Canceled {
117				finalStatus = "aborted"
118				finalError = "execution cancelled"
119			} else if scanErr := scanner.Err(); scanErr != nil {
120				finalStatus = "failed"
121				finalError = fmt.Sprintf("stdout read error: %v", scanErr)
122			} else if exitErr != nil {
123				finalStatus = "failed"
124				finalError = fmt.Sprintf("hermes exited with error: %v", exitErr)
125			}
126	
127			resCh <- Result{
128				Status:     finalStatus,
129				Output:     output.String(),
130				Error:      finalError,
131				DurationMs: duration.Milliseconds(),
132				SessionID:  sessionID,
133			}
134		}()
135	
136		return &Session{Messages: msgCh, Result: resCh}, nil
137	}

