import fs from "node:fs/promises";
import path from "node:path";
import { chromium } from "@playwright/test";

const BASE_URL = process.env.BASE_URL || "http://127.0.0.1:13000";
const ADMIN_EMAIL = process.env.SUPER_ADMIN_EMAIL;
const ADMIN_PASSWORD = process.env.SUPER_ADMIN_PASSWORD;

if (!ADMIN_EMAIL || !ADMIN_PASSWORD) {
  throw new Error("SUPER_ADMIN_EMAIL and SUPER_ADMIN_PASSWORD are required");
}

const outDir = path.join("/tmp", "multica-browser-verify");
await fs.mkdir(outDir, { recursive: true });

function assert(condition, message) {
  if (!condition) throw new Error(message);
}

const browser = await chromium.launch({ headless: true });
const page = await browser.newPage({ baseURL: BASE_URL });

try {
  await page.goto(`${BASE_URL}/login`);
  await page.waitForLoadState("networkidle");

  await page.getByRole("tab", { name: "Super Admin" }).click();
  await page.locator("#admin-email").fill(ADMIN_EMAIL);
  await page.locator("#password").fill(ADMIN_PASSWORD);
  await page.getByRole("button", { name: "Sign in as admin" }).click();
  await page.waitForURL(/\/issues/);
  await page.waitForLoadState("networkidle");
  await page.screenshot({ path: path.join(outDir, "01-issues-after-login.png"), fullPage: true });

  const auth = await page.evaluate(async () => {
    const token = localStorage.getItem("multica_token");
    const workspaceId = localStorage.getItem("multica_workspace_id");
    return { token, workspaceId };
  });
  assert(auth.token, "login did not populate multica_token");
  assert(auth.workspaceId, "login did not populate multica_workspace_id");

  const now = Date.now();
  const seed = `browser-${now}`;

  const result = await page.evaluate(async ({ token, workspaceId, seed }) => {
    const headers = {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${token}`,
      "X-Workspace-ID": workspaceId,
    };

    async function fetchJson(url, init = {}) {
      const res = await fetch(url, {
        credentials: "include",
        ...init,
        headers: {
          ...(init.headers || {}),
          ...headers,
        },
      });
      let data = null;
      try {
        data = await res.json();
      } catch {
        data = null;
      }
      if (!res.ok) {
        throw new Error(`${url} failed: ${res.status} ${JSON.stringify(data)}`);
      }
      return data;
    }

    const register = await fetchJson("/api/daemon/register", {
      method: "POST",
      body: JSON.stringify({
        workspace_id: workspaceId,
        daemon_id: `browser-daemon-${seed}`,
        device_name: "Browser Verification",
        cli_version: "browser-test",
        runtimes: [
          {
            name: `Hermes Browser Runtime ${seed}`,
            type: "hermes",
            version: "test-hermes",
            status: "online",
            capabilities: {
              structured_stream: false,
              native_resume: false,
              native_plan_mode: false,
              approval_callback: false,
              trajectory_file: false,
              pty_only: false,
            },
          },
          {
            name: `Codex Browser Runtime ${seed}`,
            type: "codex",
            version: "test-codex",
            status: "online",
            capabilities: {
              structured_stream: true,
              native_resume: true,
              native_plan_mode: false,
              approval_callback: true,
              trajectory_file: false,
              pty_only: false,
            },
          },
        ],
      }),
    });

    const runtimes = register.runtimes;
    const hermesRuntime = runtimes.find((r) => r.provider === "hermes");
    const codexRuntime = runtimes.find((r) => r.provider === "codex");
    if (!hermesRuntime || !codexRuntime) {
      throw new Error(`expected hermes and codex runtimes, got ${JSON.stringify(runtimes)}`);
    }

    const hermesAgent = await fetchJson("/api/agents", {
      method: "POST",
      body: JSON.stringify({
        name: `Hermes Browser Agent ${seed}`,
        runtime_id: hermesRuntime.id,
        visibility: "workspace",
        max_concurrent_tasks: 2,
      }),
    });

    const codexAgent = await fetchJson("/api/agents", {
      method: "POST",
      body: JSON.stringify({
        name: `Codex Browser Agent ${seed}`,
        runtime_id: codexRuntime.id,
        visibility: "workspace",
        max_concurrent_tasks: 2,
      }),
    });

    const issue = await fetchJson("/api/issues", {
      method: "POST",
      body: JSON.stringify({
        title: `Browser fanout issue ${seed}`,
        status: "todo",
        priority: "medium",
        assignee_type: "agent",
        assignee_id: hermesAgent.id,
      }),
    });

    const initialRuns = await fetchJson(`/api/issues/${issue.id}/task-runs`);
    const rootTask = initialRuns[0];
    if (!rootTask?.id) {
      throw new Error(`expected initial root task, got ${JSON.stringify(initialRuns)}`);
    }

    const claim = await fetchJson(`/api/daemon/runtimes/${hermesRuntime.id}/tasks/claim`, {
      method: "POST",
      body: JSON.stringify({}),
    });
    if (!claim.task?.id || claim.task.id !== rootTask.id) {
      throw new Error(`expected to claim root task ${rootTask.id}, got ${JSON.stringify(claim)}`);
    }

    await fetchJson(`/api/daemon/tasks/${rootTask.id}/start`, {
      method: "POST",
      body: JSON.stringify({}),
    });

    const fanout = await fetchJson(`/api/issues/${issue.id}/fanout`, {
      method: "POST",
      body: JSON.stringify({
        parent_task_id: rootTask.id,
        tasks: [
          { agent_id: hermesAgent.id, mode: "build", role: "reviewer" },
          { agent_id: codexAgent.id, mode: "build", role: "tester" },
        ],
      }),
    });

    if (!Array.isArray(fanout.tasks) || fanout.tasks.length !== 2) {
      throw new Error(`expected 2 fanout tasks, got ${JSON.stringify(fanout)}`);
    }

    const blockedClaim = await fetchJson(`/api/daemon/runtimes/${codexRuntime.id}/tasks/claim`, {
      method: "POST",
      body: JSON.stringify({}),
    });
    if (blockedClaim.task !== null) {
      throw new Error(`expected codex child claim to be blocked while root is active, got ${JSON.stringify(blockedClaim)}`);
    }

    const runs = await fetchJson(`/api/issues/${issue.id}/task-runs`);
    const children = runs.filter((task) => task.parent_task_id === rootTask.id);
    if (children.length !== 2) {
      throw new Error(`expected 2 child tasks in runs, got ${JSON.stringify(runs)}`);
    }
    const roles = children.map((task) => task.swarm_role).sort();
    if (roles.join(",") !== "reviewer,tester") {
      throw new Error(`unexpected child roles ${JSON.stringify(roles)}`);
    }
    if (!children.every((task) => task.status === "queued")) {
      throw new Error(`expected queued child tasks, got ${JSON.stringify(children)}`);
    }

    const runtimesList = await fetchJson("/api/runtimes");
    const hermesRuntimeFromList = runtimesList.find((runtime) => runtime.id === hermesRuntime.id);
    if (!hermesRuntimeFromList?.metadata?.capabilities || hermesRuntimeFromList.metadata.capabilities.native_resume !== false) {
      throw new Error(`unexpected hermes runtime metadata ${JSON.stringify(hermesRuntimeFromList)}`);
    }

    return {
      workspaceId,
      issueId: issue.id,
      rootTaskId: rootTask.id,
      hermesRuntimeId: hermesRuntime.id,
      codexRuntimeId: codexRuntime.id,
      hermesAgentId: hermesAgent.id,
      codexAgentId: codexAgent.id,
      childRoles: roles,
      runtimesCount: runtimesList.length,
    };
  }, { token: auth.token, workspaceId: auth.workspaceId, seed });

  await page.goto(`${BASE_URL}/runtimes`);
  await page.waitForLoadState("networkidle");
  await page.getByText(`Hermes Browser Runtime ${seed}`).waitFor();
  await page.screenshot({ path: path.join(outDir, "02-runtimes.png"), fullPage: true });

  await page.goto(`${BASE_URL}/issues/${result.issueId}`);
  await page.waitForLoadState("networkidle");
